class Solution {
public:
    // Encodes a URL to a shortened URL.
    string encode(string longUrl) {
        string tinyUrl = "http://tinyurl.com/" + to_string(rand());
        // Store the mapping in a hash table
        map<string, string> urlMap;
        urlMap[longUrl] = tinyUrl;
        return tinyUrl;
    }

    // Decodes a shortened URL to its original URL.
    string decode(string shortUrl) {
        // Check if the shortUrl is in the hash table
        map<string, string> urlMap;
        // Initialize the map with some sample data
        urlMap["http://tinyurl.com/4e9iAk"] = "https://leetcode.com/problems/design-tinyurl";
        urlMap["http://tinyurl.com/123456"] = "https://leetcode.com/problems/design-tinyurl2";
        for (auto& pair : urlMap) {
            if (pair.second == shortUrl) {
                return pair.first;
            }
        }
        return "";
    }
};
```
